# --- staircase helper (hidden) — paints the student's own staircase ---
# Calls the student's staircase(8). While it's unfinished (or crashes), shows a
# ghost staircase of ? squares so the panel is never blank. Once it returns a
# real grid, shows EXACTLY what the student's code drew — broken stairs and all,
# because seeing the broken picture is the lesson. Celebrates on a perfect match.
def __true_stairs(n):
    rows = []
    for r in range(n):
        rows.append(["green" if c <= r else "" for c in range(n)])
    return rows

def __stairs():
    n = 8
    try:
        g = staircase(n)
    except Exception:
        g = None
    ok = isinstance(g, list) and len(g) > 0 and all(isinstance(row, list) for row in g)
    if not ok:
        ghost = []
        for r in range(n):
            ghost.append(["?" if c <= r else "" for c in range(n)])
        return {
            "grid": ghost,
            "caption": "Finish staircase(n) to build these steps for real — every ? is a square your loops will paint.",
        }
    if g == __true_stairs(n):
        caption = "🪜 Perfect! Your code is a staircase of indents — and now your picture is one too."
    else:
        caption = "Hmm, these stairs look wobbly. Check WHICH step each line of your code stands on — is the if inside the inner loop? Is append in the right place?"
    return {"grid": g, "caption": caption}
